### 5. EXAMPLE: How Sequential Scan Works

**File:** `/workspace/src/backend/executor/nodeSeqscan.c` (lines 206-280)

The SeqScan node initializes different ExecProcNode variants based on the presence of qualifications and projections:

```c
SeqScanState *
ExecInitSeqScan(SeqScan *node, EState *estate, int eflags)
{
    SeqScanState *scanstate;

    scanstate = makeNode(SeqScanState);

    /* Open the scan relation */
    scanstate->ss.ss_currentRelation =
        ExecOpenScanRelation(estate,
                             node->scan.scanrelid,
                             eflags);

    /* Create slot for tuples from the table */
    ExecInitScanTupleSlot(estate, &scanstate->ss,
                          RelationGetDescr(scanstate->ss.ss_currentRelation),
                          table_slot_callbacks(scanstate->ss.ss_currentRelation));

    /* Initialize qual (WHERE clause) */
    scanstate->ss.ps.qual =
        ExecInitQual(node->scan.plan.qual, (PlanState *) scanstate);

    /* Choose the right variant based on qual and projection */
    if (scanstate->ss.ps.state->es_epq_active != NULL)
        scanstate->ss.ps.ExecProcNode = ExecSeqScanEPQ;
    else if (scanstate->ss.ps.qual == NULL)
    {
        if (scanstate->ss.ps.ps_ProjInfo == NULL)
            scanstate->ss.ps.ExecProcNode = ExecSeqScan;
        else
            scanstate->ss.ps.ExecProcNode = ExecSeqScanWithProject;
    }
    else
    {
        if (scanstate->ss.ps.ps_ProjInfo == NULL)
            scanstate->ss.ps.ExecProcNode = ExecSeqScanWithQual;
        else
            scanstate->ss.ps.ExecProcNode = ExecSeqScanWithQualProject;
    }

    return scanstate;
}
```

**The basic SeqScan function:**

```c
static TupleTableSlot *
ExecSeqScan(PlanState *pstate)
{
    SeqScanState *node = castNode(SeqScanState, pstate);

    return ExecScanExtended(&node->ss,
                            (ExecScanAccessMtd) SeqNext,
                            (ExecScanRecheckMtd) SeqRecheck,
                            NULL,   /* no EPQ */
                            NULL,   /* no qual */
                            NULL);  /* no projection */
}
```

**The SeqNext function** (access method):

```c
static TupleTableSlot *
SeqNext(SeqScanState *node)
{
    TableScanDesc scandesc = node->ss.ss_currentScanDesc;
    EState *estate = node->ss.ps.state;
    TupleTableSlot *slot = node->ss.ss_ScanTupleSlot;

    if (scandesc == NULL)
    {
        /* Begin the scan */
        scandesc = table_beginscan(node->ss.ss_currentRelation,
                                   estate->es_snapshot,
                                   0, NULL);
        node->ss.ss_currentScanDesc = scandesc;
    }

    /* Get the next tuple from the table */
    if (table_scan_getnextslot(scandesc, estate->es_direction, slot))
        return slot;  /* Return the slot with the tuple */

    return NULL;  /* End of scan */
}
```

