typedef struct PlanState
{
    NodeTag type;

    Plan *plan;              /* associated Plan node */
    EState *state;           /* execution state */

    ExecProcNodeMtd ExecProcNode;      /* function to return next tuple */
    ExecProcNodeMtd ExecProcNodeReal;  /* actual function if above is wrapper */

    Instrumentation *instrument;  /* runtime statistics */
    WorkerInstrumentation *worker_instrument;

    /* Common structural data */
    ExprState *qual;                    /* boolean qual condition (WHERE) */
    struct PlanState *lefttree;         /* outer child */
    struct PlanState *righttree;        /* inner child */

    List *initPlan;          /* Init SubPlanState nodes */
    List *subPlan;           /* SubPlanState nodes in expressions */

    Bitmapset *chgParam;     /* set of IDs of changed parameters */

    TupleDesc ps_ResultTupleDesc;       /* node's return type */
    TupleTableSlot *ps_ResultTupleSlot; /* slot for result tuples */
    ExprContext *ps_ExprContext;        /* expression evaluation context */
    ProjectionInfo *ps_ProjInfo;        /* projection (SELECT list) */

    bool async_capable;
    TupleDesc scandesc;

