} PlanState;
```

#### **TupleTableSlot - How Tuples are Passed Between Operators**
**File:** `/workspace/src/include/executor/tuptable.h` (lines 93-226)

```c
typedef struct TupleTableSlot
{
    NodeTag type;
    uint16 tts_flags;        /* Boolean states */
    AttrNumber tts_nvalid;   /* # of valid values in tts_values */
    const TupleTableSlotOps *const tts_ops;  /* slot type operations */
    TupleDesc tts_tupleDescriptor;           /* slot's tuple descriptor */
